import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DeviceStatus {
  ONLINE = '在线',
  OFFLINE = '离线',
  WORKING = '工作中',
  IDLE = '待命'
}

export interface Insight {
  id: string;
  time: string;
  type: 'pickup' | 'place' | 'warn';
  content: string;
  imageUrl?: string;
}

export interface RobotTask {
  id: string;
  name: string;
  status: 'pending' | 'running' | 'completed';
  timestamp: string;
}

import React, { useState } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import HomeView from './views/HomeView';
import LiveView from './views/LiveView';
import AIView from './views/AIView';
import RobotView from './views/RobotView';
import { 
  Home, 
  Camera, 
  Sparkles, 
  Bot, 
  Settings 
} from 'lucide-react';

const Navigation = () => {
  const location = useLocation();
  const navItems = [
    { path: '/', label: '首页', icon: Home },
    { path: '/live', label: '实时', icon: Camera },
    { path: '/ai', label: '分析', icon: Sparkles },
    { path: '/robot', label: '机器人', icon: Bot },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex justify-around items-center h-16 safe-bottom z-50">
      {navItems.map((item) => {
        const Icon = item.icon;
        const isActive = location.pathname === item.path;
        return (
          <Link
            key={item.path}
            to={item.path}
            className={`flex flex-col items-center justify-center w-full h-full transition-colors ${
              isActive ? 'text-blue-600' : 'text-slate-400'
            }`}
          >
            <Icon size={24} />
            <span className="text-[10px] mt-1 font-medium">{item.label}</span>
          </Link>
        );
      })}
    </nav>
  );
};

const Header = () => (
  <header className="sticky top-0 bg-white/80 backdrop-blur-md z-40 border-b border-slate-100 px-4 py-3 flex justify-between items-center">
    <h1 className="text-xl font-bold text-slate-800">桌面清理助手</h1>
    <button className="p-2 text-slate-500 hover:bg-slate-100 rounded-full transition-colors">
      <Settings size={20} />
    </button>
  </header>
);

const App: React.FC = () => {
  return (
    <Router>
      <div className="flex flex-col min-h-screen pb-16">
        <Header />
        <main className="flex-1 overflow-x-hidden">
          <Routes>
            <Route path="/" element={<HomeView />} />
            <Route path="/live" element={<LiveView />} />
            <Route path="/ai" element={<AIView />} />
            <Route path="/robot" element={<RobotView />} />
          </Routes>
        </main>
        <Navigation />
      </div>
    </Router>
  );
};

export default App;

import React from 'react';
import { DeviceStatus } from '../types';
import { ShieldCheck, Zap, Activity } from 'lucide-react';

const StatusCard: React.FC<{ title: string; status: DeviceStatus; color: string; icon: React.ReactNode }> = ({ title, status, color, icon }) => (
