    <div className="flex justify-between items-start mb-2">
      <div className={`p-2 rounded-lg ${color} bg-opacity-10`}>
        {icon}
      </div>
      <span className={`text-xs font-semibold px-2 py-1 rounded-full ${color} bg-opacity-10`}>
        {status}
      </span>
    </div>
