export default HomeView;

import React, { useState } from 'react';
import { Maximize2, RefreshCw, Radio, Camera as CameraIcon } from 'lucide-react';

const LiveView: React.FC = () => {
  const [isRefreshing, setIsRefreshing] = useState(false);

  const handleRefresh = () => {
    setIsRefreshing(true);
    setTimeout(() => setIsRefreshing(false), 1500);
  };

  return (
    <div className="p-4 flex flex-col gap-4">
      {/* 视频容器 */}
      <div className="relative aspect-[16/9] bg-slate-900 rounded-2xl overflow-hidden shadow-xl border border-slate-800">
        <div className="absolute inset-0 flex items-center justify-center">
          {/* 这里是后续对接实时流的位置 */}
          <div className="text-center text-slate-500 space-y-2">
            <Radio className="mx-auto animate-pulse text-red-500" size={48} />
            <p className="text-sm font-medium">正在连接视频流...</p>
          </div>
        </div>

        {/* 覆盖层控件 */}
        <div className="absolute top-4 left-4 bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded flex items-center gap-1">
          <span className="w-1.5 h-1.5 bg-white rounded-full animate-pulse" />
          LIVE
        </div>

        <div className="absolute bottom-4 right-4 flex gap-2">
          <button className="p-2 bg-black/40 backdrop-blur-md rounded-lg text-white">
            <Maximize2 size={18} />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <button 
          onClick={handleRefresh}
          className="flex items-center justify-center gap-2 bg-white p-4 rounded-xl border border-slate-200 shadow-sm active:bg-slate-50 transition-colors"
        >
          <RefreshCw size={18} className={`text-blue-500 ${isRefreshing ? 'animate-spin' : ''}`} />
          <span className="text-sm font-medium text-slate-700">刷新画面</span>
        </button>
        <button className="flex items-center justify-center gap-2 bg-white p-4 rounded-xl border border-slate-200 shadow-sm active:bg-slate-50 transition-colors">
          <CameraIcon size={18} className="text-blue-500" />
          <span className="text-sm font-medium text-slate-700">截图保存</span>
        </button>
      </div>

      <div className="mt-4 bg-blue-50 border border-blue-100 rounded-2xl p-4">
        <h4 className="text-blue-800 text-sm font-bold mb-2 flex items-center gap-2">
          <span className="p-1 bg-blue-500 rounded-full w-2 h-2" />
          智能边缘检测
        </h4>
        <p className="text-xs text-blue-600 leading-relaxed">
          当前监控视野覆盖桌面 100%。AI 算法正在后台分析物体摆放规律，发现异常将实时推送。
        </p>
      </div>

      {/* 占位符供后续接入模型反馈 */}
      <div className="mt-2 bg-slate-100 border border-dashed border-slate-300 rounded-2xl p-10 flex flex-col items-center justify-center text-slate-400">
        <p className="text-sm">此处将显示实时识别标签</p>
      </div>
    </div>
  );
};

export default LiveView;

import React, { useState, useEffect } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { Brain, Lightbulb, CheckCircle2, MessageSquare, AlertCircle } from 'lucide-react';

const AIView: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<any[]>([]);

  // 模拟从后端获取分析建议，后续可替换为真实的 Gemini API 调用
  const fetchMockInsights = async () => {
    setLoading(true);
    // 模拟网络延迟
    await new Promise(resolve => setTimeout(resolve, 1500));

    setSuggestions([
      {
        id: '1',
        title: '整理建议',
        content: '检测到桌面右侧有三个空水杯，建议将其移至厨房清洗。',
        type: 'cleanup',
        impact: '提升整洁度 15%'
      },
      {
        id: '2',
        title: '拿取提醒',
        content: '你即将在下午3点进行线上会议，耳机已在监控视野左下方，请注意取用。',
        type: 'reminder',
        impact: '准备效率提升'
      },
      {
        id: '3',
        title: '空间优化',
        content: '桌面中间的书籍堆放略显凌乱，建议竖向排列以节省 20% 的可用面积。',
        type: 'optimize',
        impact: '空间利用率提升'
      }
    ]);
    setLoading(false);
  };

  useEffect(() => {
    fetchMockInsights();
  }, []);

  return (
    <div className="p-4 space-y-6">
      <div className="bg-slate-900 rounded-2xl p-6 text-white overflow-hidden relative">
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-2">
            <Brain className="text-blue-400" size={24} />
            <h2 className="text-lg font-bold">智能大脑分析中</h2>
          </div>
          <p className="text-slate-400 text-sm mb-4">分析过去 2 小时的桌面活动情况...</p>
          <button 
            onClick={fetchMockInsights}
            disabled={loading}
            className="bg-blue-600 hover:bg-blue-700 disabled:opacity-50 px-4 py-2 rounded-xl text-sm font-semibold transition-all active:scale-95"
          >
            {loading ? '分析中...' : '重新分析'}
          </button>
        </div>
        <div className="absolute -right-8 -bottom-8 opacity-20">
          <Brain size={160} />
        </div>
      </div>

      <div className="space-y-4">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
          <Lightbulb size={18} className="text-amber-500" />
          针对性建议
        </h3>

        {loading ? (
          <div className="space-y-4">
            {[1, 2].map(i => (
              <div key={i} className="bg-white p-4 rounded-2xl border border-slate-100 animate-pulse h-28" />
            ))}
          </div>
        ) : (
          suggestions.map((item) => (
            <div key={item.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex gap-4">
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <span className={`w-2 h-2 rounded-full ${item.type === 'cleanup' ? 'bg-orange-500' : 'bg-blue-500'}`} />
                  <h4 className="text-sm font-bold text-slate-800">{item.title}</h4>
                </div>
                <p className="text-sm text-slate-600 leading-snug">{item.content}</p>
                <div className="mt-3 flex items-center justify-between">
                  <span className="text-[10px] font-bold bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase">
                    {item.impact}
                  </span>
                  <button className="text-xs text-blue-600 font-bold flex items-center gap-1">
                    执行建议 <CheckCircle2 size={12} />
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      <div className="bg-amber-50 border border-amber-100 rounded-2xl p-4 flex gap-3">
        <AlertCircle className="text-amber-500 shrink-0" size={20} />
        <div className="text-xs text-amber-800 leading-relaxed">
          <b>专家小贴士：</b> 根据你的使用习惯，保持桌面右侧 20cm 为空，可以显著降低工作焦虑感。
        </div>
      </div>
    </div>
  );
};

export default AIView;

import React, { useState } from 'react';
import { Trash2, LayoutGrid, Play, Power, Loader2, Battery, Thermometer } from 'lucide-react';

const RobotView: React.FC = () => {
  const [taskStatus, setTaskStatus] = useState<'idle' | 'cleaning' | 'organizing'>('idle');

  const handleCommand = (type: 'cleaning' | 'organizing') => {
    setTaskStatus(type);
    setTimeout(() => {
      setTaskStatus('idle');
      alert(`任务: ${type === 'cleaning' ? '清理垃圾' : '整理桌面'} 已完成！`);
    }, 5000);
  };

  return (
    <div className="p-4 space-y-6">
      {/* 状态看板 */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center relative">
            <div className={`absolute inset-0 bg-blue-500/10 rounded-2xl ${taskStatus !== 'idle' ? 'animate-ping' : ''}`} />
            <img 
              src="https://img.icons8.com/color/96/000000/roomba.png" 
              alt="robot" 
              className="w-12 h-12 relative z-10"
            />
          </div>
          <div>
            <h2 className="font-bold text-slate-800">ClearBot v2.1</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className={`w-2 h-2 rounded-full ${taskStatus === 'idle' ? 'bg-green-500' : 'bg-blue-500 animate-pulse'}`} />
              <span className="text-xs text-slate-500 font-medium">
                {taskStatus === 'idle' ? '待命状态' : '正在执行任务...'}
              </span>
            </div>
          </div>
        </div>
        <button className="p-3 bg-red-50 text-red-500 rounded-2xl">
          <Power size={24} />
        </button>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center gap-3">
          <Battery size={20} className="text-green-500" />
          <div>
            <div className="text-[10px] text-slate-400 uppercase font-bold">电量</div>
            <div className="text-sm font-bold text-slate-800">88%</div>
          </div>
        </div>
        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center gap-3">
          <Thermometer size={20} className="text-orange-500" />
          <div>
            <div className="text-[10px] text-slate-400 uppercase font-bold">温度</div>
            <div className="text-sm font-bold text-slate-800">32°C</div>
          </div>
        </div>
      </div>

      {/* 核心功能指令区 */}
      <div className="space-y-4">
        <h3 className="font-bold text-slate-800">核心指令</h3>

        <button 
          onClick={() => handleCommand('cleaning')}
          disabled={taskStatus !== 'idle'}
          className={`w-full p-5 rounded-2xl flex items-center justify-between transition-all active:scale-95 shadow-md ${
            taskStatus === 'cleaning' ? 'bg-blue-600 text-white' : 'bg-white text-slate-800 border border-slate-200'
          }`}
        >
          <div className="flex items-center gap-4">
            <div className={`p-3 rounded-xl ${taskStatus === 'cleaning' ? 'bg-white/20' : 'bg-red-50 text-red-500'}`}>
              <Trash2 size={24} />
            </div>
            <div className="text-left">
              <div className="font-bold">收纳清理</div>
              <div className={`text-xs ${taskStatus === 'cleaning' ? 'text-blue-100' : 'text-slate-400'}`}>
                收拾桌面及地面的垃圾
              </div>
            </div>
          </div>
          {taskStatus === 'cleaning' ? <Loader2 className="animate-spin" /> : <Play size={20} className="text-slate-300" />}
        </button>

        <button 
          onClick={() => handleCommand('organizing')}
          disabled={taskStatus !== 'idle'}
          className={`w-full p-5 rounded-2xl flex items-center justify-between transition-all active:scale-95 shadow-md ${
            taskStatus === 'organizing' ? 'bg-indigo-600 text-white' : 'bg-white text-slate-800 border border-slate-200'
          }`}
        >
          <div className="flex items-center gap-4">
            <div className={`p-3 rounded-xl ${taskStatus === 'organizing' ? 'bg-white/20' : 'bg-indigo-50 text-indigo-500'}`}>
              <LayoutGrid size={24} />
            </div>
            <div className="text-left">
              <div className="font-bold">物品归位</div>
              <div className={`text-xs ${taskStatus === 'organizing' ? 'text-indigo-100' : 'text-slate-400'}`}>
                检测异常并整理桌面物品
              </div>
            </div>
          </div>
          {taskStatus === 'organizing' ? <Loader2 className="animate-spin" /> : <Play size={20} className="text-slate-300" />}
        </button>
      </div>

      <div className="bg-slate-100 rounded-2xl p-4">
        <h4 className="text-xs font-bold text-slate-400 mb-2 uppercase tracking-wider">当前任务队列</h4>
        {taskStatus === 'idle' ? (
          <p className="text-sm text-slate-400 italic">暂无进行中的任务</p>
        ) : (
          <div className="flex items-center gap-3">
             <Loader2 size={16} className="text-blue-500 animate-spin" />
             <span className="text-sm font-medium text-slate-700">正在执行：{taskStatus === 'cleaning' ? '收拾垃圾' : '桌面整理'}</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default RobotView;

